// ═══════════════════════════════════════════════
// utils.js — Pure utility functions
// No Firebase or external dependencies here.
// ═══════════════════════════════════════════════


// ── cleanEditorHTML ───────────────────────────
// Strips empty paragraphs, script tags, and excess newlines from editor HTML.
export function cleanEditorHTML(html) {
  if (!html) return '';
  html = html.replace(/<script.*?>.*?<\/script>/gi, '');
  html = html.replace(/<p>\s*<\/p>/g, '');
  html = html.replace(/\n\s*\n/g, '\n');
  return html.trim();
}


// ── sanitize ─────────────────────────────────
// Sanitizes HTML using DOMPurify to remove XSS risks.
// Requires DOMPurify to be loaded globally.
export function sanitize(html) {
  if (!html) return '';
  // Use DOMPurify if available (loaded in admin.html), fall back to regex for other pages
  if (typeof DOMPurify !== 'undefined') {
    return DOMPurify.sanitize(html, { ALLOWED_TAGS: ['p', 'br', 'strong', 'em', 'u', 'h1', 'h2', 'h3', 'h4', 'h5', 'h6', 'ul', 'ol', 'li', 'a', 'img', 'blockquote', 'pre', 'code', 'div', 'span'], ALLOWED_ATTR: ['href', 'src', 'alt', 'title', 'class'] });
  }
  // Fallback for pages without DOMPurify
  html = html.replace(/<(script|style|iframe|object|embed|form)[^>]*>[\s\S]*?<\/\1>/gi, '');
  html = html.replace(/<(script|style|iframe|object|embed|form)[^>]*/gi, '');
  html = html.replace(/\s+on\w+\s*=\s*["'][^"']*["']/gi, '');
  html = html.replace(/\s+on\w+\s*=\s*[^\s>]*/gi, '');
  html = html.replace(/(href|src)\s*=\s*["']\s*javascript:[^"']*/gi, '$1="#"');
  return html;
}


// ── validateImageUrl ──────────────────────
// Validates image URL for safety (protocol, domain).
export function validateImageUrl(url) {
  if (!url) return null;
  try {
    const u = new URL(url);
    // Only allow https protocol
    if (u.protocol !== 'https:') return null;
    // Whitelist safe image domains
    const safeDomains = ['cloudinary.com', 'pollinations.ai', 'images.unsplash.com', 'images.pexels.com'];
    const hostname = u.hostname.toLowerCase();
    if (!safeDomains.some(domain => hostname.endsWith(domain))) {
      // Allow data URLs for local/generated images
      if (!url.startsWith('data:image/')) return null;
    }
    return url;
  } catch (_) {
    return null;
  }
}


// ── fetchWithTimeout ──────────────────────
// Wrapper for fetch with configurable timeout.
export async function fetchWithTimeout(url, options = {}, timeout = 30000) {
  const controller = new AbortController();
  const timeoutId = setTimeout(() => controller.abort(), timeout);
  try {
    const response = await fetch(url, { ...options, signal: controller.signal });
    clearTimeout(timeoutId);
    return response;
  } catch (err) {
    clearTimeout(timeoutId);
    if (err.name === 'AbortError') {
      throw new Error(`Request timeout after ${timeout}ms`);
    }
    throw err;
  }
}


// ── slugify ───────────────────────────────────
// Converts a string to a URL-safe slug.
export function slugify(text) {
  if (!text) return '';
  return text.toLowerCase().trim()
    .replace(/[^\w\s-]/g, '')
    .replace(/[\s_]+/g, '-')
    .replace(/--+/g, '-')
    .replace(/^-+|-+$/g, '');
}
// Expose on window for inline onclick handlers in admin.html
window.slugify = slugify;


// ── stripTags ─────────────────────────────────
// Removes all HTML tags and returns plain text.
export function stripTags(html) {
  if (!html) return '';
  return html.replace(/<[^>]*>/g, '').trim();
}


// ── showToast ─────────────────────────────────
// Displays a brief notification at the top-right of the screen.
// type: 'success' | 'error' | 'info'
let _toastTimer = null;
export function showToast(message, type = 'success') {
  let toast = document.getElementById('_bpToast');
  if (!toast) {
    toast = document.createElement('div');
    toast.id = '_bpToast';
    toast.style.cssText = [
      'position:fixed', 'top:1.2rem', 'right:1.2rem', 'z-index:99999',
      'padding:0.65rem 1.1rem', 'border-radius:4px', 'font-size:0.82rem',
      'font-weight:600', 'font-family:var(--sans,sans-serif)',
      'max-width:340px', 'box-shadow:0 4px 20px rgba(0,0,0,0.4)',
      'transition:opacity 0.3s', 'pointer-events:none'
    ].join(';');
    document.body.appendChild(toast);
  }
  const colors = {
    success: { bg: 'rgba(34,197,94,0.15)',  border: 'rgba(34,197,94,0.4)',  color: '#4ade80' },
    error:   { bg: 'rgba(239,68,68,0.15)',  border: 'rgba(239,68,68,0.4)',  color: '#fca5a5' },
    info:    { bg: 'rgba(59,130,246,0.15)', border: 'rgba(59,130,246,0.4)', color: '#93c5fd' },
  };
  const c = colors[type] || colors.info;
  toast.style.background = c.bg;
  toast.style.border     = `1px solid ${c.border}`;
  toast.style.color      = c.color;
  toast.style.opacity    = '1';
  toast.textContent      = message;
  clearTimeout(_toastTimer);
  _toastTimer = setTimeout(() => { toast.style.opacity = '0'; }, 3500);
}


// ── setBtnLoading ─────────────────────────────
// Toggles a button's loading state (disabled + spinner + label).
export function setBtnLoading(btnId, txtId, spinnerId, loading, label = '') {
  const btn     = document.getElementById(btnId);
  const txt     = document.getElementById(txtId);
  const spinner = document.getElementById(spinnerId);
  if (btn)     btn.disabled          = loading;
  if (txt)     txt.textContent       = label || (loading ? '…' : '');
  if (spinner) spinner.style.display = loading ? 'inline-block' : 'none';
}


// ── parseAIJson ───────────────────────────────
// Safely extracts and parses the first JSON object from an AI text response.
export function parseAIJson(text) {
  if (!text) return null;
  try {
    const s = text.indexOf('{');
    const e = text.lastIndexOf('}');
    if (s === -1 || e === -1 || e <= s) return null;
    return JSON.parse(text.substring(s, e + 1));
  } catch (_) {
    return null;
  }
}


// ── RateLimiter ────────────────────────────────
// Prevents API calls from being made too frequently.
// Usage: const limiter = new RateLimiter(2000); // 1 call per 2s
//        if (!limiter.canRequest()) return; // Check before calling API
export class RateLimiter {
  constructor(minIntervalMs = 2000) {
    this.minIntervalMs = minIntervalMs;
    this.lastRequestTime = 0;
    this.isWaiting = false;
  }

  canRequest() {
    const now = Date.now();
    const timeSinceLastRequest = now - this.lastRequestTime;
    if (timeSinceLastRequest >= this.minIntervalMs) {
      this.lastRequestTime = now;
      this.isWaiting = false;
      return true;
    }
    this.isWaiting = true;
    return false;
  }

  getWaitTime() {
    const now = Date.now();
    const timeSinceLastRequest = now - this.lastRequestTime;
    return Math.max(0, this.minIntervalMs - timeSinceLastRequest);
  }

  reset() {
    this.lastRequestTime = 0;
    this.isWaiting = false;
  }
}

// ═══════════════════════════════════════════════
// config.js — Barrel re-exporter
//
// All other modules import from here exactly as before.
// Internally, concerns are split into focused files:
//
//   firebase.js       → Firebase app, auth, db, remoteConfig
//   remote-config.js  → AI_KEYS + loadRemoteConfig
//   utils.js          → sanitize, slugify, showToast, etc.
//   constants.js      → CLOUDINARY_CLOUD_NAME, etc.
// ═══════════════════════════════════════════════

// Firebase instances
export { auth, db }                  from './firebase.js';

// AI keys + remote config loader
export { AI_KEYS, loadRemoteConfig } from './remote-config.js';

// Utility functions
export {
  cleanEditorHTML,
  sanitize,
  slugify,
  stripTags,
  showToast,
  setBtnLoading,
  parseAIJson,
  validateImageUrl,
  fetchWithTimeout,
  RateLimiter,
}                                    from './utils.js';

// App constants
export {
  CLOUDINARY_CLOUD_NAME,
  CLOUDINARY_UPLOAD_PRESET,
}                                    from './constants.js';

import { runTextAI }  from "./ai/text-engine.js";
import { runCodeAI }  from "./ai/code-engine.js";
import { runImageAI } from "./ai/image-engine.js";
import { enhancePrompt, savePattern } from "./ai-memory.js";
import { RateLimiter, showToast } from "./config.js";

const cache    = new Map();
const CACHE_TTL = 10 * 60 * 1000;

// Rate limiters for different AI operations
const textLimiter = new RateLimiter(2000);   // 1 request per 2 seconds
const codeLimiter = new RateLimiter(2000);   // 1 request per 2 seconds
const imageLimiter = new RateLimiter(5000);  // 1 request per 5 seconds

// Provider display metadata — label + color + model shown in the modal
export const PROVIDER_META = {
  groq:        { label: 'Kimi K2 (Groq)',       color: '#f55036', icon: '🌙', model: 'kimi-k2-instruct'        },
  openrouter:  { label: 'Qwen3 235B',            color: '#7c3aed', icon: '🐼', model: 'qwen3-235b-a22b'          },
  together:    { label: 'DeepSeek V3',           color: '#0ea5e9', icon: '🔍', model: 'DeepSeek-V3'              },
  deepinfra:   { label: 'Llama 3.3 70B',         color: '#10b981', icon: '🦙', model: 'Llama-3.3-70B-Instruct'  },
  gemini:      { label: 'Gemini 2.0 Flash',      color: '#4285f4', icon: '✨', model: 'gemini-2.0-flash'         },
  mistral:     { label: 'Mistral Large',         color: '#ff6b35', icon: '🌀', model: 'mistral-large-latest'     },
  deepseek:    { label: 'DeepSeek Chat',         color: '#3b82f6', icon: '💬', model: 'deepseek-chat'            },
  cloudflare:  { label: 'Cloudflare AI',         color: '#f6821f', icon: '☁️', model: 'workers-ai'               },
  pollinations:{ label: 'Pollinations',          color: '#ec4899', icon: '🌸', model: 'flux-schnell'             },
  huggingface: { label: 'HuggingFace',           color: '#fbbf24', icon: '🤗', model: 'flux-schnell'             },
};

// callAI supports two calling conventions:
//   1. callAI(prompt, "text"|"code"|"image") → raw string (legacy)
//   2. callAI(prompt, true, model, maxTokens) → { text, error, provider }
export async function callAI(prompt, type = "text", _model = null, _maxTokens = null) {
  const returnObject = (type === true || type === false);
  const actualType   = returnObject ? "text" : (type || "text");

  // ── Rate limiting checks ────────────────────────
  let limiter;
  if (actualType === "text") limiter = textLimiter;
  else if (actualType === "code") limiter = codeLimiter;
  else if (actualType === "image") limiter = imageLimiter;

  if (limiter && !limiter.canRequest()) {
    const waitTime = Math.ceil(limiter.getWaitTime() / 1000);
    const msg = `Please wait ${waitTime}s before the next ${actualType} generation.`;
    if (returnObject) return { text: "", error: msg, provider: null };
    showToast(msg, 'info');
    throw new Error(msg);
  }

  // ── Cache logic: separate keys for base vs enhanced prompts ─
  // This prevents cache invalidation when pattern memory changes
  const baseCacheKey = actualType + ":base:" + prompt;
  const baseCache = cache.get(baseCacheKey);
  if (baseCache && Date.now() - baseCache.time < CACHE_TTL) {
    const v = baseCache.value;
    return returnObject ? { text: v.text || v, error: null, provider: v.provider || null } : (v.text || v);
  }

  // ── Enhance prompt with past successful patterns ──────────
  // Only for text/code calls — not image generation
  const enhancedPrompt = (actualType !== 'image')
    ? await enhancePrompt(prompt)
    : prompt;

  // Check enhanced cache (expires faster, only 5 min)
  const enhancedCacheKey = actualType + ":enhanced:" + enhancedPrompt;
  const enhancedCache = cache.get(enhancedCacheKey);
  if (enhancedCache && Date.now() - enhancedCache.time < 5 * 60 * 1000) {
    const v = enhancedCache.value;
    return returnObject ? { text: v.text || v, error: null, provider: v.provider || null } : (v.text || v);
  }

  try {
    let result;   // { text, provider }

    if (actualType === "text")       result = await runTextAI(enhancedPrompt);
    else if (actualType === "code")  result = await runCodeAI(enhancedPrompt);
    else if (actualType === "image") result = { text: await runImageAI(prompt), provider: 'image' };
    else result = await runTextAI(enhancedPrompt);

    // Cache both base and enhanced results
    cache.set(baseCacheKey, { value: result, time: Date.now() });
    cache.set(enhancedCacheKey, { value: result, time: Date.now() });

    // ── Save pattern if result looks successful ───────────────
    // Score heuristic: non-empty result with reasonable length = 80
    if (result.text && result.text.length > 50 && actualType !== 'image') {
      const score = result.text.length > 200 ? 85 : 72;
      // Add error handling to pattern save
      savePattern(prompt, result, score).catch(err => {
        console.warn('Failed to save pattern:', err.message);
      });
    }

    return returnObject
      ? { text: result.text || "", error: null, provider: result.provider || null }
      : result.text;

  } catch (err) {
    if (returnObject) return { text: "", error: err.message, provider: null };
    throw err;
  }
}

// ═══════════════════════════════════════════════
// ai-tools.js — Inline AI Tools suite (AIT cards)
// Fixes: status showing, English enforcement,
//        aitLoading works even when body is hidden,
//        aitOpenCluster exposed globally
// ═══════════════════════════════════════════════
import { callAI }    from './ai-core.js';
import { showToast, slugify, sanitize, db } from './config.js';
import { state }     from './state.js';
import { addDoc, collection, serverTimestamp } from "https://www.gstatic.com/firebasejs/10.12.2/firebase-firestore.js";

const EN = 'Respond ONLY in English. No preamble, no reasoning. Return ONLY the JSON requested.';

// ── Helpers ───────────────────────────────────
function aitLoading(id, on) {
  // Open the body panel if it's hidden so status is visible
  const body = document.getElementById(`ait-${id}-body`);
  if (on && body && body.style.display === 'none') {
    body.style.display = 'block';
    const chev = document.getElementById(`ait-${id}-chev`);
    if (chev) chev.textContent = '▾';
  }
  const btn = body?.querySelector('.ait-run-btn');
  const sp  = document.getElementById(`sp-${id}`);
  if (btn) btn.disabled = on;
  if (sp)  sp.style.display = on ? 'inline-block' : 'none';
  // Show "running" status immediately
  if (on) aitShowResult(id, `<div style="color:var(--muted);font-size:0.75rem;display:flex;align-items:center;gap:6px"><span style="display:inline-block;width:10px;height:10px;border:2px solid var(--gold);border-top-color:transparent;border-radius:50%;animation:spin 0.7s linear infinite"></span> Running…</div>`);
}

function aitShowResult(id, html) {
  const el = document.getElementById(`res-${id}`);
  if (!el) return;
  el.style.display = 'block';
  el.innerHTML = html;
}

function aitGetTopic() {
  return document.getElementById('postTitle')?.value.trim()
      || document.getElementById('v2TopicPrompt')?.value.trim()
      || document.getElementById('aiPrompt')?.value.trim()
      || 'fintech article';
}

function aitParse(text) {
  if (!text) return null;
  try {
    const s = text.indexOf('{'), e = text.lastIndexOf('}');
    if (s !== -1 && e !== -1) return JSON.parse(text.substring(s, e + 1));
  } catch(_) {}
  return null;
}

window.toggleAIT = (id) => {
  const body = document.getElementById(`ait-${id}-body`);
  const chev = document.getElementById(`ait-${id}-chev`);
  if (!body) return;
  const open = body.style.display !== 'none';
  body.style.display = open ? 'none' : 'block';
  if (chev) chev.textContent = open ? '▸' : '▾';
};

function aitOpenCluster(title) {
  window.showView?.('editor');
  window.clearEditor?.();
  const titleEl  = document.getElementById('postTitle');
  const slugEl   = document.getElementById('postSlug');
  const promptEl = document.getElementById('v2TopicPrompt') || document.getElementById('aiPrompt');
  if (titleEl)  titleEl.value  = title;
  if (slugEl)   slugEl.value   = slugify(title);
  if (promptEl) promptEl.value = title;
  showToast(`New post: "${title.substring(0, 40)}"`, 'success');
}
window.aitOpenCluster = aitOpenCluster; // expose globally for onclick handlers

// ── Event delegation for AI tool clicks ─────────
// Instead of inline onclick handlers, we use event delegation on result containers
function attachAIToolListeners(containerId, handler) {
  const container = document.getElementById(containerId);
  if (!container) return;
  container.addEventListener('click', (e) => {
    const item = e.target.closest('.ait-result-item[data-value]');
    if (!item) return;
    const value = item.dataset.value;
    if (value) handler(value);
  });
}


// ── 2. Headline AI ────────────────────────────
window.aitRunHeadlines = async () => {
  const topic = aitGetTopic();
  const count = document.getElementById('ait-hl-count')?.value || 8;
  aitLoading('hl', true);
  const result = await callAI(
    `Generate ${count} high-CTR fintech blog headlines about: "${topic}". ${EN}
{"headlines":[{"title":"headline","score":0-100,"type":"how-to|listicle|question|stat|urgency"}]}`,
    true
  );
  aitLoading('hl', false);
  const parsed = aitParse(result.text);
  if (parsed?.headlines?.length) {
    const sorted = [...parsed.headlines].sort((a, b) => b.score - a.score);
    aitShowResult('hl', sorted.map(h => `
      <div class="ait-result-item" style="cursor:pointer" data-value="${sanitize(h.title)}">
        <div style="font-size:0.75rem;font-weight:700;color:var(--gold);flex-shrink:0;min-width:28px">${h.score}</div>
        <div><div class="ait-ri-text">${sanitize(h.title)}</div><div class="ait-ri-sub">${sanitize(h.type || '')}</div></div>
      </div>`).join(''));
    // Setup event delegation for headlines
    const container = document.getElementById('res-hl');
    if (container) {
      container.replaceWith(container.cloneNode(true)); // Remove old listeners
      const newContainer = document.getElementById('res-hl');
      newContainer.addEventListener('click', (e) => {
        const item = e.target.closest('.ait-result-item[data-value]');
        if (!item) return;
        const title = item.dataset.value;
        document.getElementById('postTitle').value = title;
        document.getElementById('postSlug').value = slugify(title);
        showToast('Headline applied!', 'success');
      });
    }
  } else {
    aitShowResult('hl', `<div style="color:#fca5a5">✕ ${result.error || 'No headlines returned'}</div>`);
  }
};


// ── 3. Traffic Predictor ─────────────────────
window.aitRunTraffic = async () => {
  const topic = aitGetTopic();
  const kw    = document.getElementById('ait-traffic-kw')?.value.trim() || topic;
  aitLoading('traffic', true);
  const result = await callAI(
    `Estimate monthly Google search traffic for: "${kw}" in fintech India niche. ${EN}
{"monthly_searches":"12,000","difficulty":45,"competition":"medium","cpc":"₹12","opportunity":"high|medium|low","trend":"growing|stable|declining"}`,
    true
  );
  aitLoading('traffic', false);
  const parsed = aitParse(result.text);
  if (parsed) {
    const oppColor = { high: 'var(--green)', medium: 'var(--gold)', low: 'var(--muted)' }[parsed.opportunity] || 'var(--muted)';
    const trendIcon = { growing: '📈', stable: '➡️', declining: '📉' }[parsed.trend] || '';
    aitShowResult('traffic', `
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:0.4rem;margin-bottom:0.5rem">
        <div class="ait-metric"><div class="ait-metric-label">Monthly Searches</div><div class="ait-metric-value">${parsed.monthly_searches}</div></div>
        <div class="ait-metric"><div class="ait-metric-label">Difficulty</div><div class="ait-metric-value">${parsed.difficulty}/100</div></div>
        <div class="ait-metric"><div class="ait-metric-label">Competition</div><div class="ait-metric-value">${parsed.competition}</div></div>
        <div class="ait-metric"><div class="ait-metric-label">CPC</div><div class="ait-metric-value">${parsed.cpc || '—'}</div></div>
      </div>
      <div style="display:flex;justify-content:space-between;align-items:center">
        <span style="font-size:0.72rem;font-weight:700;color:${oppColor}">Opportunity: ${(parsed.opportunity || '').toUpperCase()}</span>
        <span style="font-size:0.72rem;color:var(--muted)">${trendIcon} ${parsed.trend || ''}</span>
      </div>`);
  } else {
    aitShowResult('traffic', `<div style="color:#fca5a5">✕ ${result.error || 'Failed'}</div>`);
  }
};


// ── 4. Topic Clusters ────────────────────────
window.aitRunClusters = async () => {
  const topic = aitGetTopic();
  aitLoading('cluster', true);
  const result = await callAI(
    `Create 6 cluster topics for a fintech pillar article about: "${topic}". ${EN}
{"clusters":[{"title":"specific topic title","angle":"search intent in one sentence"}]}`,
    true
  );
  aitLoading('cluster', false);
  const parsed = aitParse(result.text);
  if (parsed?.clusters?.length) {
    aitShowResult('cluster', parsed.clusters.map(c => `
      <div class="ait-result-item" style="cursor:pointer" data-value="${sanitize(c.title || '')}">
        <div><div class="ait-ri-text">${sanitize(c.title)}</div><div class="ait-ri-sub">${sanitize(c.angle || '')}</div></div>
      </div>`).join(''));
    // Setup event delegation for clusters
    const container = document.getElementById('res-cluster');
    if (container) {
      container.replaceWith(container.cloneNode(true));
      const newContainer = document.getElementById('res-cluster');
      newContainer.addEventListener('click', (e) => {
        const item = e.target.closest('.ait-result-item[data-value]');
        if (!item) return;
        aitOpenCluster(item.dataset.value);
      });
    }
  } else {
    aitShowResult('cluster', `<div style="color:#fca5a5">✕ ${result.error || 'Failed'}</div>`);
  }
};


// ── 5. Content Calendar ──────────────────────
window.aitRunCalendar = async () => {
  const topic    = aitGetTopic();
  const category = document.getElementById('ait-cal-cat')?.value || 'Fintech';
  aitLoading('cal', true);
  const result = await callAI(
    `Plan 8 blog posts for a 30-day content calendar. Topic: "${topic}". Category: ${category}. ${EN}
{"posts":[{"day":1,"title":"post title","hook":"one sentence hook"},{"day":5,"title":"","hook":""},{"day":8,"title":"","hook":""},{"day":12,"title":"","hook":""},{"day":15,"title":"","hook":""},{"day":19,"title":"","hook":""},{"day":22,"title":"","hook":""},{"day":26,"title":"","hook":""}]}`,
    true
  );
  aitLoading('cal', false);
  const parsed = aitParse(result.text);
  if (parsed?.posts?.length) {
    aitShowResult('cal', parsed.posts.map(p => `
      <div class="ait-result-item" style="cursor:pointer" data-value="${sanitize(p.title || '')}">
        <div style="font-size:0.65rem;font-weight:700;color:var(--gold);flex-shrink:0;min-width:24px">D${p.day}</div>
        <div><div class="ait-ri-text">${sanitize(p.title)}</div><div class="ait-ri-sub">${sanitize(p.hook || '')}</div></div>
      </div>`).join(''));
    // Setup event delegation for calendar
    const container = document.getElementById('res-cal');
    if (container) {
      container.replaceWith(container.cloneNode(true));
      const newContainer = document.getElementById('res-cal');
      newContainer.addEventListener('click', (e) => {
        const item = e.target.closest('.ait-result-item[data-value]');
        if (!item) return;
        aitOpenCluster(item.dataset.value);
      });
    }
  } else {
    aitShowResult('cal', `<div style="color:#fca5a5">✕ ${result.error || 'Failed'}</div>`);
  }
};


